import { createClient } from '@supabase/supabase-js';

const supabaseUrl = import.meta.env.VITE_SUPABASE_URL;
const supabaseAnonKey = import.meta.env.VITE_SUPABASE_ANON_KEY;

if (!supabaseUrl || !supabaseAnonKey) {
  throw new Error('Missing Supabase environment variables');
}

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

export const EDGE_FUNCTIONS = {
  AUTH:             '/functions/v1/admin-auth',
  GET_STATS:        '/functions/v1/admin-get-stats',
  GET_USERS:        '/functions/v1/admin-get-users',
  GET_LICENSES:     '/functions/v1/admin-get-licenses',
  GET_DEVICES:      '/functions/v1/admin-get-devices',
  CREATE_USER:      '/functions/v1/admin-create-user',
  REVOKE_LICENSE:   '/functions/v1/admin-revoke-license',
  ACTIVATE_LICENSE: '/functions/v1/admin-activate-license',
  RESET_DEVICES:    '/functions/v1/admin-reset-devices',
} as const;
